import React, { useEffect, useState } from 'react'
import * as _Util from '../store/Util';
import { useSelector } from 'react-redux'

import {  CloseModal, OpenModal, loadProdMark, updObserveChanges, getAnonymus, getDispatch } from '../actions/common'
import { BTNH_Cmpt, CheckBoxSlide_Cmpt, Cmpt_ChoosePlace } from './components';
import { selectObserveChanges, setObserveLogin } from '../store/qvamarketsSlice';



const BTNH = BTNH_Cmpt();
const CheckBoxSlide = CheckBoxSlide_Cmpt();
const PlaceCity = Cmpt_ChoosePlace()





const ProfileModal = (props) => {
  const observeChanges =  useSelector(selectObserveChanges);

  const { data } = props;
  const {  modalID } = data;

  const [initialize, setInitialize] = useState(false);

  let _state = _Util.getStore();

  let userProfile = _state["userProfile"];

  useEffect(() => {
    if(!initialize){
      setInitialize(true);
      _Util.initGapi(()=>loadAuth());
    }
    /*
    return () => {
      _Util.updStore("showGSB",0);
      updObserveChanges();
    };
    */
  })



  const revokeAllScopes = () => {
    _Util.initGapi(()=>{
      _Util.updStore("showGSB",1);
      updObserveChanges();
      window.gapi.load('auth2', function() {
        let g = document.getElementById('g-s-b')
        g && window.gapi.signin2.render('g-s-b', {
          width: 232,
          height: 40,
          longtitle: true,
          hidden:true,
        });
        setTimeout(()=>{
          const auth2 =  window.gapi.auth2 && window.gapi.auth2.getAuthInstance();
          auth2 && auth2.disconnect();
          let _now = (new Date()).getTime();
          var _expire = (new Date(_now - 1000));
          document.cookie = `fs_us_id=${""}; expires=${_expire}; path=/;g_state = {"i_l":1,"i_p":${_expire}}`;

          window.location.href ="https://localhost:3000";
          // window.location.href ="https://jessienailsky.com";
          /*
          CloseModal({id:modalID});
          _Util.updStore("showGSB",0); 
          _Util.updStore("userProfile",null);
          getDispatch()(setObserveLogin());
          */
        },650);
      });
    });
  }



  


  let lng = window.localStorage.getItem("lng");

  const updLng = (v) => { 
    window.localStorage.setItem("lng",v?"es":"en");
    _Util.updLang();
    updObserveChanges();
  }

 
  let inV = lng === "es"?true:false;




  const openPlaceChosse = (ipr,itB) => {
    let Cdata = {};
    Cdata['zIndex']=650;
    Cdata['observeResize']=true;    
    Cdata['props']={state: userProfile["state"], city: userProfile["city"], id: userProfile["id"], minHeight: '40px'};
    Cdata['content']=<PlaceCity confirm={_confirmAdd}/>;
    OpenModal(Cdata);
  }

  const _confirmAdd = (ipr,itB) => {
    loadProdMark(modalID);
  }

  return (
    <div {...modalID?{"dialog-key-id":modalID}:""}  className={`pym81b sendBx upd_alert_bx`}>
      <style>
        {`
        .palette{
          --base-color: rgb(21, 100, 191,1);
          --base-color-gradient: 21, 100, 191;
        }
        `}
        </style>
        <div className={`delete_alert_t1 `}>
            <div>           
            { userProfile && userProfile["name"]}
            </div>
        </div>
        <div className={`delete_alert_t2 `}>
          <div>
            { userProfile && userProfile["email"]}
          </div>
        </div>

        <div className={`sendBtn _dsplFlx spaceAround _mrgSwith `}>    
          <div className={`in_stock_switch _dsplFlx`}>
            <span className={`sw_left_span `}>{"English"}</span>
            <div  className={`in_stock_switch_btn`}>
              <CheckBoxSlide initvalue={inV} keyCode={77} updChange={(e)=>updLng(e)}/>
            </div>
            <span className={`sw_rgh_span`}>{"Español"}</span>
          </div>
        </div>
        <div className={`sendBtn _dsplFlx spaceAround`}>          
          <div className={`fieldPadding _MrgV`} style={{ marginTop: "10px"}}>
            <span onClick={()=>revokeAllScopes()}>
              <BTNH theme={``} title={_Util.translatetext(10)}/>
            </span>
          </div>
        </div>

     


       
    </div>
    )
}


export default ProfileModal


  /*********************************************************************************************************************************************/  
  /**************************************   loadAuth load auht function and render google singin button ****************************************/
  /*********************************************************************************************************************************************/
  
  
  const loadAuth = async () => { 
    _Util.updStore("showGSB",1);
    updObserveChanges();
    window.gapi.load('auth2', function() {
      window.gapi.signin2.render('g-s-b', {
        width: 232,
        height: 40,
        longtitle: true,
        hidden:true,
      });
    });
  }